/* htmx 2.0.4 - minimal implementation for power-atlas */
(function(){
  function process(root) {
    root.querySelectorAll("[hx-get]").forEach(function(el) {
      var trigger = el.getAttribute("hx-trigger") || "click";
      var url = el.getAttribute("hx-get");
      var swap = el.getAttribute("hx-swap") || "innerHTML";
      var targetSel = el.getAttribute("hx-target");
      function doFetch() {
        var val = el.value !== undefined ? el.value : '';
        var finalUrl = url + (url.indexOf('?') === -1 && el.name ? '?'+el.name+'='+encodeURIComponent(val) : '');
        var targetEl = targetSel ? document.querySelector(targetSel) : el;
        fetch(finalUrl).then(function(r){return r.text();}).then(function(html){
          if(swap === "innerHTML" && targetEl) { targetEl.innerHTML = html; process(targetEl); }
          else if(swap === "outerHTML" && targetEl) { var temp = document.createElement('div'); temp.innerHTML = html; var newEl = temp.firstElementChild; targetEl.replaceWith(newEl); process(newEl); }
          el.dispatchEvent(new Event('htmx:afterSwap'));
          if(el.getAttribute('hx-on::after-swap')) {
            new Function(el.getAttribute('hx-on::after-swap')).call(el);
          }
        });
      }
      if(trigger.indexOf("load") !== -1) doFetch();
      if(trigger.indexOf("input") !== -1) {
        var delay = 300;
        var m = trigger.match(/delay:(\d+)ms/);
        if(m) delay = parseInt(m[1]);
        var timer;
        el.addEventListener("input", function(){clearTimeout(timer);timer=setTimeout(doFetch,delay)});
      } else if(trigger.indexOf("load") === -1) {
        el.addEventListener("click", doFetch);
      }
    });
    root.querySelectorAll("[hx-post]").forEach(function(el) {
      var url = el.getAttribute("hx-post");
      var swap = el.getAttribute("hx-swap") || "innerHTML";
      var targetSel = el.getAttribute("hx-target");
      var valsAttr = el.getAttribute("hx-vals");
      el.addEventListener("click", function(e) {
        e.preventDefault();
        var body = {};
        if(valsAttr) { try { body = JSON.parse(valsAttr); } catch(ex){} }
        var opts = {method:"POST", headers:{"Content-Type":"application/json"}, body:JSON.stringify(body)};
        fetch(url, opts).then(function(r){return r.text();}).then(function(html){
          if(swap === "none") return;
          var targetEl = targetSel ? document.querySelector(targetSel) : el;
          if(targetEl) { targetEl.innerHTML = html; process(targetEl); }
        });
      });
    });
  }
  document.addEventListener("DOMContentLoaded", function(){ process(document.body); });
  // Re-process dynamically added content
  var origInnerHTML = Object.getOwnPropertyDescriptor(Element.prototype, 'innerHTML');
  window._htmxProcess = process;
  window.htmx = {version:"2.0.4-impl", process: process};
})();
